import { createVex } from '@vex_dev/sdk/vercel';
import { generateText, streamText } from 'ai';

const vex = createVex({
  projectId: process.env.VEX_PROJECT_ID!,
  apiKey: process.env.VEX_API_KEY!,
});

export async function safeGenerateCode(prompt: string) {
  const verifier = await vex.verifier({
    name: 'code-generation',
    checks: [
      'code_safety',
      'syntax_validity',
      'no_credential_leakage',
      'dependency_safety',
    ],
  });

  const result = await verifier.run(
    generateText.bind(null, {
      model: 'gpt-4o',
      prompt,
    })
  );

  return result.value;
}

