const codeSchema = z.object({
  code: z.string().refine(isValidSyntax, 'Invalid syntax'),
  tests: z.array(z.string()),
});

export async function verifiedCodeGen(prompt: string) {
  const verifier = await vex.verifier({
    name: 'structured-code',
    schema: codeSchema,
  });

  const result = await verifier.run(async () =>
    generateObject({
      model: 'gpt-4o',
      schema: codeSchema,
      prompt,
    })
  );

  return result.value.object;
}

import { streamText } from 'ai';
import { createStreamableValue } from 'ai/rsc';
import { createVex } from '@vex_dev/sdk/vercel';

export async function safeStreamCode(prompt: string) {
  const vex = createVex({ /* config */ });
  const streamValue = createStreamableValue('');

  (async () => {
    const verifier = await vex.verifier({
      name: 'code-stream',
      checks: ['code_safety'],
    });

    const result = await verifier.run(
      streamText.bind(null, { model: 'gpt-4o', prompt })
    );

    if (result.passed) {
      streamValue.update(result.value);
    } else {
      streamValue.update('Code failed safety checks');
    }
    streamValue.done();
  })();

  return streamValue.value;
}
